function extractWithTar(tarPath, destination, onProgress) {
  const symlinks = [];

  let total = 0;
  // This takes a few seconds, but lets us show the progress
  tar.t({
    sync: true,
    file: tarPath,
    onentry() {
      total += 1;
    },
  });

  let started = 0;
  let timeout = null;

  return new Promise((resolve, reject) => {
    tar.x(
      {
        file: tarPath,
        preservePaths: true,
        cwd: destination,
        filter(path, entry) {
          if (entry.type === 'SymbolicLink') {
            symlinks.push({
              path: entry.path,
              linkPath: entry.linkpath,
            });
            return false;
          }

          return true;
        },
        onentry() {
          started += 1;

          if (!timeout) {
            timeout = setTimeout(() => {
              timeout = null;
              onProgress({
                percent: (started / total) * 100,
                fileCount: started,
              });
            }, 300);
          }
        },
      },
      err => {
        if (timeout) {
          clearTimeout(timeout);
        }

        if (err) {
          return reject(err);
        }
        createSymlinks(symlinks, destination);
        resolve();
      },
    );
  });
