class AccountsCommon {
  constructor(options) {
    // Validate config options keys
    for (const key of Object.keys(options)) {
      if (!VALID_CONFIG_KEYS.includes(key)) {
        console.error(`Accounts.config: Invalid key: ${key}`);
      }
    }

