      timeCost: Accounts._argon2TimeCost(),
      memoryCost: Accounts._argon2MemoryCost(),
      parallelism: Accounts._argon2Parallelism()
    });
  }
  else {
    return await bcryptHash(password, Accounts._bcryptRounds());
  }
