getRoundsFromBcryptHash = (hash) => {
  let rounds;
  if (hash) {
    const hashSegments = hash.split("$");
    if (hashSegments.length > 2) {
      rounds = parseInt(hashSegments[2], 10);
    }
  }
  return rounds;
