reportError = (error, callback) => {
  if (callback) {
    callback(error);
  } else {
    throw error;
  }
}

transformSelector = selector => {
  if (typeof selector !== 'string') {
    return selector;
  }

  if (selector.includes('@')) {
    return { email: selector };
  }

  return { username: selector };
}

internalPasswordlessLoginWithToken = ({
  selector,
  token,
  code,
  callback,
}) => {
  Accounts.callLoginMethod({
    methodArguments: [
      {
        selector: transformSelector(selector),
        token,
        code,
      },
    ],
    userCallback: error => {
      if (error) {
        reportError(error, callback);
      } else {
        callback && callback();
      }
    },
  });
}

checkToken = ({ selector, token }) => {
  if (!token) {
    return;
  }

  const userId = Tracker.nonreactive(Meteor.userId);

  if (!userId) {
    Meteor.passwordlessLoginWithToken(selector, token, () => {
      // Make it look clean by removing the authToken from the URL
      if (window.history) {
        const url = window.location.href.split('?')[0];

        window.history.pushState(null, null, url);
      }
    });
  }
}

