  if (!selector) {
    Accounts._handleError('A selector is necessary');
  }
  const { email, id, ...rest } = selector;
  return Meteor.users.findOneAsync(
    {
      ...rest,
      ...(id && { _id: id }),
      ...(email && { 'emails.address': email })
    },
    {
      fields: {
        services: 1,
        emails: 1,
      },
    }
  );
}

