      .attr("fill-rule", "evenodd")
      .style("fill", d => this.getColor(d.data))
      .style("opacity", 1)
      .on("mouseover", this.mouseoverEvent());

    // // Get total size of the tree = value of root node from partition.
    const totalSize = this.path.datum().value;

