storableError = error => {
  const plainObject = {};
  Object.getOwnPropertyNames(error).forEach(
    key => plainObject[key] = error[key]
  );

  // Keep track of whether it's a Meteor.Error
  if(error instanceof Meteor.Error) {
    plainObject['meteorError'] = true;
  }

  return { error: plainObject };
