_testTime = function(t) {
  if (t.events && t.events.length > 0) {
    var lastEvent = t.events[t.events.length - 1];
    if (lastEvent.type === "finish") {
      if ((typeof lastEvent.timeMs) === "number") {
        return lastEvent.timeMs;
