      options.stream.write(options.prompt);
    } else {
      rl.setPrompt(options.prompt);
      rl.prompt();
    }

    return new Promise((resolve) => {
      rl.on('line', line => {
        rl.close();
        if (! options.echo) {
          options.stream.write("\n");
        }
