    const source = this._packageSource;
    if (! inCheckout()) {
      buildmessage.error("Package.includeTool() can only be used with a " +
                         "checkout of meteor");
    } else if (source.includeTool) {
      buildmessage.error("Duplicate includeTool call");
    } else {
      source.includeTool = true;
    }
