function addScheme(hostOrURL) {
  if (hostOrURL.match(/^http/)) {
    return hostOrURL;
  } else if (hostOrURL.match(/^localhost(:\d+)?$/)) {
    return "http://" + hostOrURL;
  } else {
    return "https://" + hostOrURL;
  }
}

async function getDeployURL(site) {
  // Always trust explicitly configuration via env.
  if (process.env.DEPLOY_HOSTNAME) {
    return Promise.resolve(addScheme(process.env.DEPLOY_HOSTNAME.trim()));
  }

  const defaultURL = "https://us-east-1.galaxy-deploy.meteor.com";

  // No site? Just use the default.
  if (!site) {
    return Promise.resolve(defaultURL);
  }

  // If we have a site, we can try to do Galaxy discovery.

  // Do we already have an answer?
  if (galaxyDiscoveryCache.has(site)) {
    return galaxyDiscoveryCache.get(site);
  }

  // Otherwise, try https first, then http, then just use the default.
  const p = await discoverGalaxy(site, "https")
          .catch(async () => await discoverGalaxy(site, "http"))
          .catch(() => defaultURL);
  galaxyDiscoveryCache.set(site, p);
  return p;
}

async function discoverGalaxy(site, scheme) {
  const discoveryURL =
          scheme + "://" + site + "/.well-known/meteor/deploy-url";
  // If httpHelpers.request throws, the returned Promise will reject, which is
  // fine.
  const { response, body } = await request({
    url: discoveryURL,
    json: true,
    strictSSL: true,
    // We don't want to be confused by, eg, a non-Galaxy-hosted site which
    // redirects to a Galaxy-hosted site.
    followRedirect: false
  });
  if (response.statusCode !== 200) {
    throw new Error("bad status code: " + response.statusCode);
  }
  if (!body) {
    throw new Error("response had no body");
  }
  if (body.galaxyDiscoveryVersion !== "galaxy-1") {
    throw new Error(
      "unexpected galaxyDiscoveryVersion: " + body.galaxyDiscoveryVersion);
  }
  if (! hasOwn.call(body, "deployURL")) {
    throw new Error("no deployURL");
  }
  return body.deployURL;
}

ServiceConnection = function (endpointUrl, options) {
  const self = this;

  // ServiceConnection never should retry connections: just one TCP connection
  // is enough, and any errors on it should be detected promptly.]
  self.options = options;
  self.endpointUrl = endpointUrl;

  if (process.env.CAFILE) {
    options.npmFayeOptions = {
      ca: files.readFile(process.env.CAFILE)
    };
  }
}

packageList = function (projectContext) {
  var versions = [];
  projectContext.packageMap.eachPackage(function (name, info) {
    versions.push({
      name: name,
      version: info.version,
      local: info.kind === 'local',
      direct: !!projectContext.projectConstraintsFile.getConstraint(name)
    });
  });
  return versions;
}

recordPackages = async function (options) {
  // Before doing anything, look at the app's dependencies to see if the
  // opt-out package is there; if present, we don't record any stats.
  var packages = packageList(options.projectContext);
  if (_.findWhere(packages, { name: OPT_OUT_PACKAGE_NAME }) ||
    process.env.DO_NOT_TRACK) {
    // Print some output for the 'report-stats' self-test.
    if (process.env.METEOR_PACKAGE_STATS_TEST_OUTPUT) {
      process.stdout.write("PACKAGE STATS NOT SENT\n");
    }
    return;
  }

  var appIdentifier = options.projectContext.appIdentifier;

  // We do this inside a new fiber to avoid blocking anything on talking
  // to the package stats server. If we can't connect, for example, we
  // don't care; we'll just miss out on recording these packages.
  // This also gives it its own buildmessage state.
  // However, we do make sure to have already extracted the package list from
  // projectContext, since it might mutate out from under us otherwise.
  var details = {
    what: options.what,
    userAgent: httpHelpers.getUserAgent(),
    sessionId: auth.getSessionId(config.getAccountsDomain()),
    site: options.site
  };

  try {
    var conn = await connectToPackagesStatsServer();
    var accountsConfiguration = await auth.getAccountsConfiguration(conn);

    if (auth.isLoggedIn()) {
      try {
        await auth.loginWithTokenOrOAuth(
          conn,
          accountsConfiguration,
          config.getPackageStatsServerUrl(),
          config.getPackageStatsServerDomain(),
          "package-stats-server"
        );
      } catch (err) {
        // Do nothing. If we can't log in, we should continue and report
        // stats anonymously.
        //
        // We log other errors with `logErrorIfInCheckout`, but login
        // errors can happen in normal operation when nothing is wrong
        // (e.g. login token expired or revoked) so we don't log them.
      }
    }

    var result = await conn.call("recordAppPackages",
      appIdentifier,
      packages,
      details);

    // If the stats server sent us a new session, save it for use on
    // subsequent requests.
    if (result && result.newSessionId) {
      auth.setSessionId(config.getAccountsDomain(), result.newSessionId);
    }

    if (process.env.METEOR_PACKAGE_STATS_TEST_OUTPUT) {
      // Print some output for the 'report-stats' self-test.
      process.stdout.write("PACKAGE STATS SENT\n");
    }
  } catch (err) {
    logErrorIfInCheckout(err);
    // Do nothing. A failure to record package stats shouldn't be
    // visible to the end user and shouldn't affect whatever command
    // they are running.
  } finally {
    conn && conn.close();
  }
}

logErrorIfInCheckout = function (err) {
  if ((Console.isInteractive() && files.inCheckout())
    || process.env.METEOR_PACKAGE_STATS_TEST_OUTPUT) {
    Console.warn("Failed to record package usage.");
    Console.warn(
      "(This error is hidden when you are not running Meteor from a",
      "checkout.)");
    var printErr = err.stack || err;
    Console.rawWarn(printErr + "\n");
    Console.warn();
    Console.warn();
  }
}

getPackagesForAppIdInTest = function (projectContext) {
  var conn = connectToPackagesStatsServer();
  var result;
  try {
    result = conn.call(
      "getPackagesForAppId",
      projectContext.appIdentifier);
    if (result && result.details) {
      result.details.packages = _.sortBy(result.details.packages, "name");
    }
  } finally {
    conn.close();
  }

  return result;
}

