    await enterJob(
      {
        title: 'Installing Puppeteer in Meteor tool'
      },
      () => {
        return ensureDependencies(NPM_DEPENDENCIES);
      }
    );

    this.npmPackageExports = require('puppeteer');
    this.initialized = true;
