  }

  resetFns.push(currentJob.set(job));

  const nestingLevel = currentNestingLevel.get();
  resetFns.push(currentNestingLevel.set(nestingLevel + 1));

  var start;
  if (debugBuild) {
    start = Date.now();
    console.log(
      spaces(nestingLevel * 2),
      "START CAPTURE",
      nestingLevel,
      options.title,
      "took " + (end - start),
    );
  }

  try {
    await f();
  } finally {
    progress.reportProgressDone();

    resetFns.forEach(fn => fn());

    if (debugBuild) {
      var end = Date.now();
      console.log(
        spaces(nestingLevel * 2),
        "END CAPTURE",
